-- ============================================================
-- CHLOEX UI LIBRARY - Fixed Version
-- Perubahan:
--   1. Animasi Minimize (slide down + fade out, slide up + fade in)
--   2. Animasi Close dialog (scale in)
--   3. Lucide icon list terintegrasi
-- ============================================================

local HttpService = game:GetService("HttpService")

if not isfolder("ThanHub") then makefolder("ThanHub") end
if not isfolder("ThanHub/Config") then makefolder("ThanHub/Config") end

local gameName = tostring(game:GetService("MarketplaceService"):GetProductInfo(game.PlaceId).Name)
gameName = gameName:gsub("[^%w_ ]", ""):gsub("%s+", "_")

local ConfigFile = "ThanHub/Config/than" .. gameName .. ".json"

ConfigData      = {}
Elements        = {}
CURRENT_VERSION = nil

function SaveConfig()
    if writefile then
        ConfigData._version = CURRENT_VERSION
        writefile(ConfigFile, HttpService:JSONEncode(ConfigData))
    end
end

function LoadConfigFromFile()
    if not CURRENT_VERSION then return end
    if isfile and isfile(ConfigFile) then
        local ok, result = pcall(function()
            return HttpService:JSONDecode(readfile(ConfigFile))
        end)
        if ok and type(result) == "table" then
            ConfigData = (result._version == CURRENT_VERSION) and result or { _version = CURRENT_VERSION }
        else
            ConfigData = { _version = CURRENT_VERSION }
        end
    else
        ConfigData = { _version = CURRENT_VERSION }
    end
end

function LoadConfigElements()
    for key, element in pairs(Elements) do
        if ConfigData[key] ~= nil and element.Set then
            element:Set(ConfigData[key], true)
        end
    end
end

