-- ============================================================
-- HELPER: resolve icon string → full rbxassetid string
-- ============================================================
local function resolveIcon(icon)
    if not icon or icon == "" then return nil end
    -- Already a full asset URL
    if icon:sub(1, 13) == "rbxassetid://" then return icon end
    -- Short name lookup (internal or lucide)
    if Icons[icon] then return Icons[icon] end
    -- Fallback: treat as bare number / unknown
    return icon
end

local UserInputService = game:GetService("UserInputService")
local TweenService     = game:GetService("TweenService")
local LocalPlayer      = game:GetService("Players").LocalPlayer
local Mouse            = LocalPlayer:GetMouse()
local CoreGui          = game:GetService("CoreGui")
local viewport         = workspace.CurrentCamera.ViewportSize

local function isMobileDevice()
    return UserInputService.TouchEnabled
        and not UserInputService.KeyboardEnabled
        and not UserInputService.MouseEnabled
end
local isMobile = isMobileDevice()

local function safeSize(pxWidth, pxHeight)
    local scaleX = pxWidth  / viewport.X
    local scaleY = pxHeight / viewport.Y
    if isMobile then
        if scaleX > 0.5 then scaleX = 0.5 end
        if scaleY > 0.3 then scaleY = 0.3 end
    end
    return UDim2.new(scaleX, 0, scaleY, 0)
end

local function MakeDraggable(topbarobject, object)
    local function CustomPos(topbar, obj)
        local Dragging, DragInput, DragStart, StartPosition
        topbar.InputBegan:Connect(function(input)
            if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
                Dragging    = true
                DragStart   = input.Position
                StartPosition = obj.Position
                input.Changed:Connect(function()
                    if input.UserInputState == Enum.UserInputState.End then Dragging = false end
                end)
            end
        end)
        topbar.InputChanged:Connect(function(input)
            if input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch then
                DragInput = input
            end
        end)
        UserInputService.InputChanged:Connect(function(input)
            if input == DragInput and Dragging then
                local Delta = input.Position - DragStart
                TweenService:Create(obj, TweenInfo.new(0.2), {
                    Position = UDim2.new(
                        StartPosition.X.Scale, StartPosition.X.Offset + Delta.X,
                        StartPosition.Y.Scale, StartPosition.Y.Offset + Delta.Y
                    )
                }):Play()
            end
        end)
    end

    local function CustomSize(obj)
        local Dragging, DragInput, DragStart, StartSize
        local minSizeX, minSizeY = 100, 100
        local defSizeX = isMobile and 470 or 640
        local defSizeY = isMobile and 270 or 400
        obj.Size = UDim2.new(0, defSizeX, 0, defSizeY)

        local handle = Instance.new("Frame")
        handle.AnchorPoint        = Vector2.new(1, 1)
        handle.BackgroundTransparency = 1
        handle.Size     = UDim2.new(0, 40, 0, 40)
        handle.Position = UDim2.new(1, 20, 1, 20)
        handle.Name     = "changesizeobject"
        handle.Parent   = obj

        handle.InputBegan:Connect(function(input)
            if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
                Dragging  = true
                DragStart = input.Position
                StartSize = obj.Size
                input.Changed:Connect(function()
                    if input.UserInputState == Enum.UserInputState.End then Dragging = false end
                end)
            end
        end)
        handle.InputChanged:Connect(function(input)
            if input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch then
                DragInput = input
            end
        end)
        UserInputService.InputChanged:Connect(function(input)
            if input == DragInput and Dragging then
                local Delta = input.Position - DragStart
                TweenService:Create(obj, TweenInfo.new(0.2), {
                    Size = UDim2.new(0,
                        math.max(StartSize.X.Offset + Delta.X, minSizeX), 0,
                        math.max(StartSize.Y.Offset + Delta.Y, minSizeY))
                }):Play()
            end
        end)
    end

    CustomSize(object)
    CustomPos(topbarobject, object)
end

function CircleClick(Button, X, Y)
    task.spawn(function()
        Button.ClipsDescendants = true
        local Circle = Instance.new("ImageLabel")
        Circle.Image              = "rbxassetid://85779221265543"
        Circle.ImageColor3        = Color3.fromRGB(80, 80, 80)
        Circle.ImageTransparency  = 0.9
        Circle.BackgroundTransparency = 1
        Circle.ZIndex             = 10
        Circle.Name               = "Circle"
        Circle.Parent             = Button

        local NewX = X - Circle.AbsolutePosition.X
        local NewY = Y - Circle.AbsolutePosition.Y
        Circle.Position = UDim2.new(0, NewX, 0, NewY)
        local Size = math.max(Button.AbsoluteSize.X, Button.AbsoluteSize.Y) * 1.5
        local Time = 0.5
        Circle:TweenSizeAndPosition(
            UDim2.new(0, Size, 0, Size),
            UDim2.new(0.5, -Size/2, 0.5, -Size/2),
            "Out", "Quad", Time, false, nil
        )
        for i = 1, 10 do
            Circle.ImageTransparency = Circle.ImageTransparency + 0.01
            task.wait(Time / 10)
        end
        Circle:Destroy()
    end)
end

