local Chloex = {}
function Chloex:MakeNotify(NotifyConfig)
    NotifyConfig             = NotifyConfig or {}
    NotifyConfig.Title       = NotifyConfig.Title or "Than-Hub"
    NotifyConfig.Description = NotifyConfig.Description or "Notification"
    NotifyConfig.Content     = NotifyConfig.Content or "Content"
    NotifyConfig.Color       = NotifyConfig.Color or Color3.fromRGB(255, 0, 255)
    NotifyConfig.Time        = NotifyConfig.Time or 0.5
    NotifyConfig.Delay       = NotifyConfig.Delay or 5

    local NotifyFunction = {}
    task.spawn(function()
        if not CoreGui:FindFirstChild("NotifyGui") then
            local ng = Instance.new("ScreenGui")
            ng.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
            ng.Name   = "NotifyGui"
            ng.Parent = CoreGui
        end
        if not CoreGui.NotifyGui:FindFirstChild("NotifyLayout") then
            local nl = Instance.new("Frame")
            nl.AnchorPoint         = Vector2.new(1, 1)
            nl.BackgroundTransparency = 0.999
            nl.BorderSizePixel     = 0
            nl.Position            = UDim2.new(1, -30, 1, -30)
            nl.Size                = UDim2.new(0, 320, 1, 0)
            nl.Name                = "NotifyLayout"
            nl.Parent              = CoreGui.NotifyGui
            local Count = 0
            nl.ChildRemoved:Connect(function()
                Count = 0
                for _, v in nl:GetChildren() do
                    TweenService:Create(v, TweenInfo.new(0.3, Enum.EasingStyle.Quad, Enum.EasingDirection.InOut), {
                        Position = UDim2.new(0, 0, 1, -((v.Size.Y.Offset + 12) * Count))
                    }):Play()
                    Count = Count + 1
                end
            end)
        end

        local NotifyPosHeigh = 0
        for _, v in CoreGui.NotifyGui.NotifyLayout:GetChildren() do
            NotifyPosHeigh = -(v.Position.Y.Offset) + v.Size.Y.Offset + 12
        end

        local NotifyFrame     = Instance.new("Frame")
        local NotifyFrameReal = Instance.new("Frame")
        local UICorner        = Instance.new("UICorner")
        local Top             = Instance.new("Frame")
        local TextLabel       = Instance.new("TextLabel")
        local UICorner1       = Instance.new("UICorner")
        local TextLabel1      = Instance.new("TextLabel")
        local Close           = Instance.new("TextButton")
        local ImageLabel      = Instance.new("ImageLabel")
        local TextLabel2      = Instance.new("TextLabel")

        NotifyFrame.BackgroundTransparency = 1
        NotifyFrame.Size      = UDim2.new(1, 0, 0, 150)
        NotifyFrame.Name      = "NotifyFrame"
        NotifyFrame.AnchorPoint = Vector2.new(0, 1)
        NotifyFrame.Position  = UDim2.new(0, 0, 1, -NotifyPosHeigh)
        NotifyFrame.Parent    = CoreGui.NotifyGui.NotifyLayout

        NotifyFrameReal.BackgroundColor3  = Color3.fromRGB(0, 0, 0)
        NotifyFrameReal.BorderSizePixel   = 0
        NotifyFrameReal.Position = UDim2.new(0, 400, 0, 0)
        NotifyFrameReal.Size     = UDim2.new(1, 0, 1, 0)
        NotifyFrameReal.Name     = "NotifyFrameReal"
        NotifyFrameReal.Parent   = NotifyFrame
        UICorner.CornerRadius    = UDim.new(0, 8)
        UICorner.Parent          = NotifyFrameReal

        Top.BackgroundTransparency = 0.999
        Top.BorderSizePixel        = 0
        Top.Size                   = UDim2.new(1, 0, 0, 36)
        Top.Name                   = "Top"
        Top.Parent                 = NotifyFrameReal

        TextLabel.Font             = Enum.Font.GothamBold
        TextLabel.Text             = NotifyConfig.Title
        TextLabel.TextColor3       = Color3.fromRGB(255, 255, 255)
        TextLabel.TextSize         = 14
        TextLabel.TextXAlignment   = Enum.TextXAlignment.Left
        TextLabel.BackgroundTransparency = 0.999
        TextLabel.BorderSizePixel  = 0
        TextLabel.Size             = UDim2.new(1, 0, 1, 0)
        TextLabel.Position         = UDim2.new(0, 10, 0, 0)
        TextLabel.Parent           = Top
        UICorner1.CornerRadius     = UDim.new(0, 5)
        UICorner1.Parent           = Top

        TextLabel1.Font            = Enum.Font.GothamBold
        TextLabel1.Text            = NotifyConfig.Description
        TextLabel1.TextColor3      = NotifyConfig.Color
        TextLabel1.TextSize        = 14
        TextLabel1.TextXAlignment  = Enum.TextXAlignment.Left
        TextLabel1.BackgroundTransparency = 0.999
        TextLabel1.BorderSizePixel = 0
        TextLabel1.Size            = UDim2.new(1, 0, 1, 0)
        TextLabel1.Position        = UDim2.new(0, TextLabel.TextBounds.X + 15, 0, 0)
        TextLabel1.Parent          = Top

        Close.Text                 = ""
        Close.AnchorPoint          = Vector2.new(1, 0.5)
        Close.BackgroundTransparency = 0.999
        Close.BorderSizePixel      = 0
        Close.Position             = UDim2.new(1, -5, 0.5, 0)
        Close.Size                 = UDim2.new(0, 25, 0, 25)
        Close.Name                 = "Close"
        Close.Parent               = Top

        ImageLabel.Image           = "rbxassetid://9886659671"
        ImageLabel.AnchorPoint     = Vector2.new(0.5, 0.5)
        ImageLabel.BackgroundTransparency = 0.999
        ImageLabel.BorderSizePixel = 0
        ImageLabel.Position        = UDim2.new(0.49, 0, 0.5, 0)
        ImageLabel.Size            = UDim2.new(1, -8, 1, -8)
        ImageLabel.Parent          = Close

        TextLabel2.Font            = Enum.Font.GothamBold
        TextLabel2.Text            = NotifyConfig.Content
        TextLabel2.TextColor3      = Color3.fromRGB(150, 150, 150)
        TextLabel2.TextSize        = 13
        TextLabel2.TextXAlignment  = Enum.TextXAlignment.Left
        TextLabel2.TextYAlignment  = Enum.TextYAlignment.Top
        TextLabel2.BackgroundTransparency = 0.999
        TextLabel2.BorderSizePixel = 0
        TextLabel2.Position        = UDim2.new(0, 10, 0, 27)
        TextLabel2.Size            = UDim2.new(1, -20, 0, 13)
        TextLabel2.Parent          = NotifyFrameReal
        TextLabel2.Size            = UDim2.new(1, -20, 0, 13 + (13 * (TextLabel2.TextBounds.X // TextLabel2.AbsoluteSize.X)))
        TextLabel2.TextWrapped     = true

        NotifyFrame.Size = UDim2.new(1, 0, 0,
            TextLabel2.AbsoluteSize.Y < 27 and 65 or TextLabel2.AbsoluteSize.Y + 40)

        local waitbruh = false
        function NotifyFunction:Close()
            if waitbruh then return false end
            waitbruh = true
            TweenService:Create(NotifyFrameReal,
                TweenInfo.new(tonumber(NotifyConfig.Time), Enum.EasingStyle.Back, Enum.EasingDirection.InOut),
                { Position = UDim2.new(0, 400, 0, 0) }):Play()
            task.wait(tonumber(NotifyConfig.Time) / 1.2)
            NotifyFrame:Destroy()
        end

        Close.Activated:Connect(function() NotifyFunction:Close() end)
        TweenService:Create(NotifyFrameReal,
            TweenInfo.new(tonumber(NotifyConfig.Time), Enum.EasingStyle.Back, Enum.EasingDirection.InOut),
            { Position = UDim2.new(0, 0, 0, 0) }):Play()
        task.wait(tonumber(NotifyConfig.Delay))
        NotifyFunction:Close()
    end)
    return NotifyFunction
end

function than(msg, delay, color, title, desc)
    return Chloex:MakeNotify({
        Title = title or "ThanHub", Description = desc or "Notification",
        Content = msg or "Content", Color = color or Color3.fromRGB(0, 208, 255), Delay = delay or 4
    })
end

