    local isMinimized = false

    Min.Activated:Connect(function()
        CircleClick(Min, Mouse.X, Mouse.Y)
        if not isMinimized then
            -- Slide the body down off-screen and fade, keep topbar visible
            isMinimized = true
            local originalPos = DropShadowHolder.Position
            local screenH     = workspace.CurrentCamera.ViewportSize.Y

            TweenService:Create(DropShadow, TweenInfo.new(0.4, Enum.EasingStyle.Quart, Enum.EasingDirection.In), {
                ImageTransparency = 1
            }):Play()
            TweenService:Create(DropShadowHolder, TweenInfo.new(0.4, Enum.EasingStyle.Quart, Enum.EasingDirection.In), {
                Position = UDim2.new(
                    originalPos.X.Scale,
                    originalPos.X.Offset,
                    originalPos.Y.Scale,
                    originalPos.Y.Offset + screenH * 0.12
                )
            }):Play()
            task.wait(0.05)
