            }):Play()
            task.wait(0.35)
            LayersTab.Visible = false
            Layers.Visible    = false
        else
            -- Slide back up + fade in
            isMinimized       = false
            LayersTab.Visible = true
            Layers.Visible    = true
            local originalPos = DropShadowHolder.Position

            TweenService:Create(Main, TweenInfo.new(0.35, Enum.EasingStyle.Back, Enum.EasingDirection.Out), {
                Size = UDim2.new(1, -47, 1, -47)
            }):Play()
            TweenService:Create(DropShadowHolder, TweenInfo.new(0.4, Enum.EasingStyle.Back, Enum.EasingDirection.Out), {
                Position = UDim2.new(
                    originalPos.X.Scale,
                    originalPos.X.Offset,
                    originalPos.Y.Scale,
                    originalPos.Y.Offset - workspace.CurrentCamera.ViewportSize.Y * 0.12
                )
            }):Play()
            TweenService:Create(DropShadow, TweenInfo.new(0.4, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {
                ImageTransparency = 0
            }):Play()
        end
    end)

    -- ============================================================
    -- CLOSE — scale-in dialog animation
    -- ============================================================
    Close.Activated:Connect(function()
        CircleClick(Close, Mouse.X, Mouse.Y)

        local Overlay = Instance.new("Frame")
        Overlay.Size                 = UDim2.new(1, 0, 1, 0)
        Overlay.BackgroundColor3     = Color3.fromRGB(0, 0, 0)
        Overlay.BackgroundTransparency = 1      -- start transparent
        Overlay.ZIndex               = 50
