        -- Animate overlay fade-in
        TweenService:Create(Overlay, TweenInfo.new(0.25), {
            BackgroundTransparency = 0.4
        }):Play()

        local Dialog = Instance.new("Frame")
        Dialog.AnchorPoint          = Vector2.new(0.5, 0.5)
