        Instance.new("UICorner", Dialog).CornerRadius = UDim.new(0, 10)

        local UIStrokeDialog = Instance.new("UIStroke")
        UIStrokeDialog.Color       = Color3.fromRGB(168, 85, 247)
        UIStrokeDialog.Thickness   = 1.5
        UIStrokeDialog.Transparency = 0.5
        UIStrokeDialog.Parent      = Dialog

        -- Scale-in animation
        TweenService:Create(Dialog, TweenInfo.new(0.3, Enum.EasingStyle.Back, Enum.EasingDirection.Out), {
            Size = UDim2.new(0, 300, 0, 150)
        }):Play()

        task.wait(0.15) -- wait a bit before showing content so it feels snappy

        local TitleLabel = Instance.new("TextLabel")
