        local function makeDialogBtn(text, xPos)
            local Btn = Instance.new("TextButton")
            Btn.Size               = UDim2.new(0.44, 0, 0, 32)
            Btn.Position           = UDim2.new(xPos, 0, 1, -42)
            Btn.BackgroundColor3   = Color3.fromRGB(255, 255, 255)
