            Btn.ZIndex             = 52
            Btn.Parent             = Dialog
            Instance.new("UICorner", Btn).CornerRadius = UDim.new(0, 6)
            return Btn
        end

        local Yes    = makeDialogBtn("Yes, Close", 0.05)
        local Cancel = makeDialogBtn("Cancel",     0.51)

        -- Hover tint helpers
        Yes.MouseEnter:Connect(function()
            TweenService:Create(Yes, TweenInfo.new(0.15), { BackgroundTransparency = 0.75 }):Play()
        end)
        Yes.MouseLeave:Connect(function()
            TweenService:Create(Yes, TweenInfo.new(0.15), { BackgroundTransparency = 0.92 }):Play()
        end)
        Cancel.MouseEnter:Connect(function()
            TweenService:Create(Cancel, TweenInfo.new(0.15), { BackgroundTransparency = 0.75 }):Play()
        end)
        Cancel.MouseLeave:Connect(function()
            TweenService:Create(Cancel, TweenInfo.new(0.15), { BackgroundTransparency = 0.92 }):Play()
        end)

        local function closeDialog()
            -- Scale-out
            TweenService:Create(Dialog, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {
                Size = UDim2.new(0, 0, 0, 0)
            }):Play()
            TweenService:Create(Overlay, TweenInfo.new(0.2), {
                BackgroundTransparency = 1
            }):Play()
            task.wait(0.22)
            Overlay:Destroy()
        end

        Yes.MouseButton1Click:Connect(function()
            -- Scale-out then destroy
            TweenService:Create(Dialog, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.In), {
                Size = UDim2.new(0, 0, 0, 0)
            }):Play()
            TweenService:Create(Overlay, TweenInfo.new(0.2), { BackgroundTransparency = 1 }):Play()
            task.wait(0.22)
            if Chloeex then Chloeex:Destroy() end
            if CoreGui:FindFirstChild("ToggleUIButton") then
                CoreGui.ToggleUIButton:Destroy()
            end
        end)

        Cancel.MouseButton1Click:Connect(closeDialog)
    end)

