                PContent.TextWrapped     = false
                PContent.RichText        = true
                PContent.Size            = UDim2.new(1, -16, 0, PContent.TextBounds.Y)
                PContent.Parent          = Paragraph

                local PButton
                if ParagraphConfig.ButtonText then
                    PButton = Instance.new("TextButton")
                    PButton.Position            = UDim2.new(0, 10, 0, 42)
                    PButton.Size                = UDim2.new(1, -22, 0, 28)
                    PButton.BackgroundTransparency = 0.935
                    PButton.Font                = Enum.Font.GothamBold
                    PButton.TextSize            = 12
                    PButton.TextTransparency    = 0.3
