                    Instance.new("UICorner", PButton).CornerRadius = UDim.new(0, 6)
                    if ParagraphConfig.ButtonCallback then
                        PButton.MouseButton1Click:Connect(ParagraphConfig.ButtonCallback)
                    end
                end

                local function UpdateSize()
                    local total = PContent.TextBounds.Y + 33
                    if PButton then total = total + PButton.Size.Y.Offset + 5 end
                    Paragraph.Size = UDim2.new(1, 0, 0, total)
                end
                UpdateSize()
                PContent:GetPropertyChangedSignal("TextBounds"):Connect(UpdateSize)

                function ParagraphFunc:SetContent(content)
                    PContent.Text = content or "Content"
                    UpdateSize()
